package com.example.oidcclient.service;

import com.example.oidcclient.config.OidcProviderConfig;
import com.example.oidcclient.model.TokenResponse;
import com.example.oidcclient.model.UserInfoResponse;
import org.slf4j.Logger;
import org.slf4j.LoggerFactory;
import org.springframework.http.HttpHeaders;
import org.springframework.http.MediaType;
import org.springframework.stereotype.Service;
import org.springframework.util.LinkedMultiValueMap;
import org.springframework.util.MultiValueMap;
import org.springframework.web.reactive.function.BodyInserters;
import org.springframework.web.reactive.function.client.WebClient;

@Service
public class TokenExchangeService {

    private static final Logger logger = LoggerFactory.getLogger(TokenExchangeService.class);

    private final OidcProviderConfig oidcProviderConfig;
    private final WebClient webClient;

    public TokenExchangeService(OidcProviderConfig oidcProviderConfig) {
        this.oidcProviderConfig = oidcProviderConfig;
        this.webClient = WebClient.builder().build();
    }

    public TokenResponse exchangeAuthorizationCode(String authorizationCode) {
        logger.info("Exchanging authorization code for tokens at: {}", oidcProviderConfig.getTokenUri());

        MultiValueMap<String, String> formData = new LinkedMultiValueMap<>();
        formData.add("grant_type", "authorization_code");
        formData.add("code", authorizationCode);
        formData.add("redirect_uri", oidcProviderConfig.getRedirectUri());
        formData.add("client_id", oidcProviderConfig.getClientId());
        formData.add("client_secret", oidcProviderConfig.getClientSecret());

        try {
            TokenResponse response = webClient.post()
                    .uri(oidcProviderConfig.getTokenUri())
                    .contentType(MediaType.APPLICATION_FORM_URLENCODED)
                    .body(BodyInserters.fromFormData(formData))
                    .retrieve()
                    .bodyToMono(TokenResponse.class)
                    .block();

            logger.info("Successfully exchanged authorization code for tokens");
            return response;
        } catch (Exception e) {
            logger.error("Failed to exchange authorization code: {}", e.getMessage(), e);
            throw new RuntimeException("Token exchange failed", e);
        }
    }

    public TokenResponse refreshAccessToken(String refreshToken) {
        logger.info("Refreshing access token at: {}", oidcProviderConfig.getTokenUri());

        MultiValueMap<String, String> formData = new LinkedMultiValueMap<>();
        formData.add("grant_type", "refresh_token");
        formData.add("refresh_token", refreshToken);
        formData.add("client_id", oidcProviderConfig.getClientId());
        formData.add("client_secret", oidcProviderConfig.getClientSecret());

        try {
            TokenResponse response = webClient.post()
                    .uri(oidcProviderConfig.getTokenUri())
                    .contentType(MediaType.APPLICATION_FORM_URLENCODED)
                    .body(BodyInserters.fromFormData(formData))
                    .retrieve()
                    .bodyToMono(TokenResponse.class)
                    .block();

            logger.info("Successfully refreshed access token");
            return response;
        } catch (Exception e) {
            logger.error("Failed to refresh token: {}", e.getMessage(), e);
            throw new RuntimeException("Token refresh failed", e);
        }
    }

    public UserInfoResponse getUserInfo(String accessToken) {
        logger.info("Fetching user info from: {}", oidcProviderConfig.getUserinfoUri());

        try {
            UserInfoResponse response = webClient.get()
                    .uri(oidcProviderConfig.getUserinfoUri())
                    .header(HttpHeaders.AUTHORIZATION, "Bearer " + accessToken)
                    .retrieve()
                    .bodyToMono(UserInfoResponse.class)
                    .block();

            logger.info("Successfully fetched user info for subject: {}",
                    response != null ? response.getSubject() : "unknown");
            return response;
        } catch (Exception e) {
            logger.error("Failed to fetch user info: {}", e.getMessage(), e);
            throw new RuntimeException("UserInfo request failed", e);
        }
    }
}

