package com.example.oidcclient.service;

import com.example.oidcclient.config.OidcProviderConfig;
import com.example.oidcclient.model.UserSessionInfo;
import com.nimbusds.jose.JWSAlgorithm;
import com.nimbusds.jose.jwk.source.JWKSource;
import com.nimbusds.jose.jwk.source.RemoteJWKSet;
import com.nimbusds.jose.proc.JWSKeySelector;
import com.nimbusds.jose.proc.JWSVerificationKeySelector;
import com.nimbusds.jose.proc.SecurityContext;
import com.nimbusds.jwt.JWTClaimsSet;
import com.nimbusds.jwt.SignedJWT;
import com.nimbusds.jwt.proc.ConfigurableJWTProcessor;
import com.nimbusds.jwt.proc.DefaultJWTProcessor;
import org.slf4j.Logger;
import org.slf4j.LoggerFactory;
import org.springframework.security.oauth2.core.oidc.OidcIdToken;
import org.springframework.stereotype.Service;

import jakarta.annotation.PostConstruct;
import java.net.URL;
import java.time.Instant;
import java.util.HashMap;
import java.util.HashSet;
import java.util.List;
import java.util.Map;

@Service
public class IdTokenParserService {

    private static final Logger logger = LoggerFactory.getLogger(IdTokenParserService.class);

    private final OidcProviderConfig oidcProviderConfig;
    private ConfigurableJWTProcessor<SecurityContext> jwtProcessor;

    public IdTokenParserService(OidcProviderConfig oidcProviderConfig) {
        this.oidcProviderConfig = oidcProviderConfig;
    }

    @PostConstruct
    public void init() {
        try {
            jwtProcessor = new DefaultJWTProcessor<>();
            JWKSource<SecurityContext> keySource = new RemoteJWKSet<>(
                    new URL(oidcProviderConfig.getJwkSetUri()));
            JWSKeySelector<SecurityContext> keySelector = new JWSVerificationKeySelector<>(
                    JWSAlgorithm.RS256, keySource);
            jwtProcessor.setJWSKeySelector(keySelector);
            logger.info("JWT processor initialized with JWK set URI: {}", oidcProviderConfig.getJwkSetUri());
        } catch (Exception e) {
            logger.error("Failed to initialize JWT processor: {}", e.getMessage(), e);
        }
    }

    public UserSessionInfo parseIdToken(String idTokenValue) {
        try {
            JWTClaimsSet claimsSet = jwtProcessor.process(idTokenValue, null);
            return buildUserSessionFromClaims(claimsSet, idTokenValue);
        } catch (Exception e) {
            logger.error("Failed to parse and validate ID token: {}", e.getMessage(), e);
            throw new RuntimeException("ID token parsing failed", e);
        }
    }

    public UserSessionInfo parseIdTokenWithoutValidation(String idTokenValue) {
        try {
            SignedJWT signedJWT = SignedJWT.parse(idTokenValue);
            JWTClaimsSet claimsSet = signedJWT.getJWTClaimsSet();
            return buildUserSessionFromClaims(claimsSet, idTokenValue);
        } catch (Exception e) {
            logger.error("Failed to parse ID token: {}", e.getMessage(), e);
            throw new RuntimeException("ID token parsing failed", e);
        }
    }

    public UserSessionInfo parseFromOidcIdToken(OidcIdToken oidcIdToken) {
        UserSessionInfo sessionInfo = new UserSessionInfo();

        sessionInfo.setSubject(oidcIdToken.getSubject());
        sessionInfo.setEmail(oidcIdToken.getEmail());
        sessionInfo.setEmailVerified(oidcIdToken.getEmailVerified() != null && oidcIdToken.getEmailVerified());
        sessionInfo.setName(oidcIdToken.getFullName());
        sessionInfo.setGivenName(oidcIdToken.getGivenName());
        sessionInfo.setFamilyName(oidcIdToken.getFamilyName());
        sessionInfo.setPicture(oidcIdToken.getPicture() != null ? oidcIdToken.getPicture().toString() : null);
        sessionInfo.setLocale(oidcIdToken.getLocale());
        sessionInfo.setIssuer(oidcIdToken.getIssuer() != null ? oidcIdToken.getIssuer().toString() : null);
        sessionInfo.setAudience(oidcIdToken.getAudience() != null ? String.join(",", oidcIdToken.getAudience()) : null);
        sessionInfo.setIssuedAt(oidcIdToken.getIssuedAt());
        sessionInfo.setExpiresAt(oidcIdToken.getExpiresAt());
        sessionInfo.setNonce(oidcIdToken.getNonce());
        sessionInfo.setIdTokenValue(oidcIdToken.getTokenValue());

        Map<String, Object> additionalClaims = new HashMap<>(oidcIdToken.getClaims());
        additionalClaims.remove("sub");
        additionalClaims.remove("email");
        additionalClaims.remove("email_verified");
        additionalClaims.remove("name");
        additionalClaims.remove("given_name");
        additionalClaims.remove("family_name");
        additionalClaims.remove("picture");
        additionalClaims.remove("locale");
        additionalClaims.remove("iss");
        additionalClaims.remove("aud");
        additionalClaims.remove("iat");
        additionalClaims.remove("exp");
        additionalClaims.remove("nonce");
        sessionInfo.setAdditionalClaims(additionalClaims);

        logger.info("Created user session from OIDC ID token for subject: {}", sessionInfo.getSubject());
        return sessionInfo;
    }

    private UserSessionInfo buildUserSessionFromClaims(JWTClaimsSet claimsSet, String idTokenValue) {
        UserSessionInfo sessionInfo = new UserSessionInfo();

        sessionInfo.setSubject(claimsSet.getSubject());
        sessionInfo.setEmail(getStringClaim(claimsSet, "email"));
        sessionInfo.setEmailVerified(getBooleanClaim(claimsSet, "email_verified"));
        sessionInfo.setName(getStringClaim(claimsSet, "name"));
        sessionInfo.setGivenName(getStringClaim(claimsSet, "given_name"));
        sessionInfo.setFamilyName(getStringClaim(claimsSet, "family_name"));
        sessionInfo.setPicture(getStringClaim(claimsSet, "picture"));
        sessionInfo.setLocale(getStringClaim(claimsSet, "locale"));
        sessionInfo.setIssuer(claimsSet.getIssuer());
        sessionInfo.setNonce(getStringClaim(claimsSet, "nonce"));
        sessionInfo.setIdTokenValue(idTokenValue);

        List<String> audience = claimsSet.getAudience();
        if (audience != null && !audience.isEmpty()) {
            sessionInfo.setAudience(String.join(",", audience));
        }

        if (claimsSet.getIssueTime() != null) {
            sessionInfo.setIssuedAt(claimsSet.getIssueTime().toInstant());
        }

        if (claimsSet.getExpirationTime() != null) {
            sessionInfo.setExpiresAt(claimsSet.getExpirationTime().toInstant());
        }

        Map<String, Object> allClaims = claimsSet.getClaims();
        Map<String, Object> additionalClaims = new HashMap<>(allClaims);
        additionalClaims.remove("sub");
        additionalClaims.remove("email");
        additionalClaims.remove("email_verified");
        additionalClaims.remove("name");
        additionalClaims.remove("given_name");
        additionalClaims.remove("family_name");
        additionalClaims.remove("picture");
        additionalClaims.remove("locale");
        additionalClaims.remove("iss");
        additionalClaims.remove("aud");
        additionalClaims.remove("iat");
        additionalClaims.remove("exp");
        additionalClaims.remove("nonce");
        sessionInfo.setAdditionalClaims(additionalClaims);

        validateClaims(sessionInfo);

        logger.info("Parsed ID token claims for subject: {}, email: {}", sessionInfo.getSubject(), sessionInfo.getEmail());
        return sessionInfo;
    }

    private void validateClaims(UserSessionInfo sessionInfo) {
        if (sessionInfo.getSubject() == null || sessionInfo.getSubject().isEmpty()) {
            throw new RuntimeException("ID token missing required 'sub' claim");
        }

        if (sessionInfo.getIssuer() != null && !sessionInfo.getIssuer().equals(oidcProviderConfig.getIssuer())) {
            logger.warn("ID token issuer '{}' does not match expected issuer '{}'",
                    sessionInfo.getIssuer(), oidcProviderConfig.getIssuer());
        }

        if (sessionInfo.getExpiresAt() != null && Instant.now().isAfter(sessionInfo.getExpiresAt())) {
            throw new RuntimeException("ID token has expired");
        }

        if (sessionInfo.getAudience() != null && !sessionInfo.getAudience().contains(oidcProviderConfig.getClientId())) {
            logger.warn("ID token audience '{}' does not contain expected client ID '{}'",
                    sessionInfo.getAudience(), oidcProviderConfig.getClientId());
        }
    }

    private String getStringClaim(JWTClaimsSet claimsSet, String claimName) {
        try {
            return claimsSet.getStringClaim(claimName);
        } catch (Exception e) {
            return null;
        }
    }

    private boolean getBooleanClaim(JWTClaimsSet claimsSet, String claimName) {
        try {
            Boolean value = claimsSet.getBooleanClaim(claimName);
            return value != null && value;
        } catch (Exception e) {
            return false;
        }
    }
}

