// ============================================================
package com.example.oidcclient.service;

import com.example.oidcclient.model.UserSessionInfo;
import org.slf4j.Logger;
import org.slf4j.LoggerFactory;
import org.springframework.stereotype.Service;

import jakarta.servlet.http.HttpSession;
import java.util.concurrent.ConcurrentHashMap;

@Service
public class UserSessionService {

    private static final Logger logger = LoggerFactory.getLogger(UserSessionService.class);
    private static final String SESSION_USER_KEY = "USER_SESSION_INFO";
    private static final long DEFAULT_SESSION_TIMEOUT = 3600;

    private final ConcurrentHashMap<String, UserSessionInfo> activeSessions = new ConcurrentHashMap<>();

    public void createSession(HttpSession httpSession, UserSessionInfo userSessionInfo) {
        httpSession.setAttribute(SESSION_USER_KEY, userSessionInfo);
        activeSessions.put(httpSession.getId(), userSessionInfo);
        logger.info("Created session for user: {} (session ID: {})",
                userSessionInfo.getEmail(), httpSession.getId());
    }

    public UserSessionInfo getSession(HttpSession httpSession) {
        UserSessionInfo sessionInfo = (UserSessionInfo) httpSession.getAttribute(SESSION_USER_KEY);
        if (sessionInfo != null && sessionInfo.isSessionExpired(DEFAULT_SESSION_TIMEOUT)) {
            logger.info("Session expired for user: {}", sessionInfo.getEmail());
            invalidateSession(httpSession);
            return null;
        }
        return sessionInfo;
    }

    public void invalidateSession(HttpSession httpSession) {
        UserSessionInfo sessionInfo = (UserSessionInfo) httpSession.getAttribute(SESSION_USER_KEY);
        if (sessionInfo != null) {
            logger.info("Invalidating session for user: {}", sessionInfo.getEmail());
            activeSessions.remove(httpSession.getId());
        }
        httpSession.invalidate();
    }

    public void updateTokens(HttpSession httpSession, String accessToken, String refreshToken) {
        UserSessionInfo sessionInfo = getSession(httpSession);
        if (sessionInfo != null) {
            sessionInfo.setAccessToken(accessToken);
            if (refreshToken != null) {
                sessionInfo.setRefreshToken(refreshToken);
            }
            httpSession.setAttribute(SESSION_USER_KEY, sessionInfo);
            activeSessions.put(httpSession.getId(), sessionInfo);
            logger.info("Updated tokens for user: {}", sessionInfo.getEmail());
        }
    }

    public int getActiveSessionCount() {
        return activeSessions.size();
    }

    public boolean isUserActive(String subject) {
        return activeSessions.values().stream()
                .anyMatch(session -> subject.equals(session.getSubject()));
    }
}

