package com.example.oidcclient.service;

import com.example.oidcclient.model.UserSessionInfo;
import org.slf4j.Logger;
import org.slf4j.LoggerFactory;
import org.springframework.security.oauth2.client.oidc.userinfo.OidcUserRequest;
import org.springframework.security.oauth2.client.oidc.userinfo.OidcUserService;
import org.springframework.security.oauth2.core.OAuth2AuthenticationException;
import org.springframework.security.oauth2.core.oidc.user.OidcUser;
import org.springframework.stereotype.Service;

@Service
public class CustomOidcUserService extends OidcUserService {

    private static final Logger logger = LoggerFactory.getLogger(CustomOidcUserService.class);

    private final IdTokenParserService idTokenParserService;

    public CustomOidcUserService(IdTokenParserService idTokenParserService) {
        this.idTokenParserService = idTokenParserService;
    }

    @Override
    public OidcUser loadUser(OidcUserRequest userRequest) throws OAuth2AuthenticationException {
        OidcUser oidcUser = super.loadUser(userRequest);

        logger.info("Loading OIDC user - Subject: {}, Email: {}",
                oidcUser.getSubject(), oidcUser.getEmail());

        UserSessionInfo sessionInfo = idTokenParserService.parseFromOidcIdToken(oidcUser.getIdToken());
        sessionInfo.setAccessToken(userRequest.getAccessToken().getTokenValue());

        if (userRequest.getAccessToken().getScopes() != null) {
            sessionInfo.setScopes(userRequest.getAccessToken().getScopes());
        }

        logger.info("OIDC user loaded successfully - Subject: {}, Name: {}, Email: {}",
                sessionInfo.getSubject(), sessionInfo.getName(), sessionInfo.getEmail());

        return oidcUser;
    }
}

