// ============================================================
package com.example.oidcclient.handler;

import com.example.oidcclient.model.UserSessionInfo;
import com.example.oidcclient.service.IdTokenParserService;
import com.example.oidcclient.service.UserSessionService;
import org.slf4j.Logger;
import org.slf4j.LoggerFactory;
import org.springframework.security.core.Authentication;
import org.springframework.security.oauth2.client.OAuth2AuthorizedClient;
import org.springframework.security.oauth2.client.OAuth2AuthorizedClientService;
import org.springframework.security.oauth2.client.authentication.OAuth2AuthenticationToken;
import org.springframework.security.oauth2.core.oidc.user.OidcUser;
import org.springframework.security.web.authentication.AuthenticationSuccessHandler;
import org.springframework.stereotype.Component;

import jakarta.servlet.ServletException;
import jakarta.servlet.http.HttpServletRequest;
import jakarta.servlet.http.HttpServletResponse;
import java.io.IOException;

@Component
public class OidcAuthenticationSuccessHandler implements AuthenticationSuccessHandler {

    private static final Logger logger = LoggerFactory.getLogger(OidcAuthenticationSuccessHandler.class);

    private final UserSessionService userSessionService;
    private final IdTokenParserService idTokenParserService;
    private final OAuth2AuthorizedClientService authorizedClientService;

    public OidcAuthenticationSuccessHandler(UserSessionService userSessionService,
                                            IdTokenParserService idTokenParserService,
                                            OAuth2AuthorizedClientService authorizedClientService) {
        this.userSessionService = userSessionService;
        this.idTokenParserService = idTokenParserService;
        this.authorizedClientService = authorizedClientService;
    }

    @Override
    public void onAuthenticationSuccess(HttpServletRequest request,
                                        HttpServletResponse response,
                                        Authentication authentication) throws IOException, ServletException {

        if (authentication instanceof OAuth2AuthenticationToken) {
            OAuth2AuthenticationToken oauthToken = (OAuth2AuthenticationToken) authentication;
            OidcUser oidcUser = (OidcUser) oauthToken.getPrincipal();

            UserSessionInfo sessionInfo = idTokenParserService.parseFromOidcIdToken(oidcUser.getIdToken());

            OAuth2AuthorizedClient authorizedClient = authorizedClientService.loadAuthorizedClient(
                    oauthToken.getAuthorizedClientRegistrationId(),
                    oauthToken.getName());

            if (authorizedClient != null) {
                sessionInfo.setAccessToken(authorizedClient.getAccessToken().getTokenValue());
                if (authorizedClient.getAccessToken().getScopes() != null) {
                    sessionInfo.setScopes(authorizedClient.getAccessToken().getScopes());
                }
                if (authorizedClient.getRefreshToken() != null) {
                    sessionInfo.setRefreshToken(authorizedClient.getRefreshToken().getTokenValue());
                }
            }

            userSessionService.createSession(request.getSession(), sessionInfo);

            logger.info("Authentication successful for user: {} ({})",
                    sessionInfo.getName(), sessionInfo.getEmail());
        }

        response.sendRedirect("/dashboard");
    }
}

