package com.example.oidcclient.controller;

import com.example.oidcclient.model.UserSessionInfo;
import com.example.oidcclient.service.UserSessionService;
import org.slf4j.Logger;
import org.slf4j.LoggerFactory;
import org.springframework.security.core.annotation.AuthenticationPrincipal;
import org.springframework.security.oauth2.core.oidc.user.OidcUser;
import org.springframework.stereotype.Controller;
import org.springframework.ui.Model;
import org.springframework.web.bind.annotation.GetMapping;

import jakarta.servlet.http.HttpSession;

@Controller
public class DashboardController {

    private static final Logger logger = LoggerFactory.getLogger(DashboardController.class);

    private final UserSessionService userSessionService;

    public DashboardController(UserSessionService userSessionService) {
        this.userSessionService = userSessionService;
    }

    @GetMapping("/dashboard")
    public String dashboard(@AuthenticationPrincipal OidcUser oidcUser,
                            HttpSession httpSession,
                            Model model) {

        UserSessionInfo sessionInfo = userSessionService.getSession(httpSession);

        if (sessionInfo == null && oidcUser != null) {
            sessionInfo = new UserSessionInfo();
            sessionInfo.setSubject(oidcUser.getSubject());
            sessionInfo.setEmail(oidcUser.getEmail());
            sessionInfo.setName(oidcUser.getFullName());
        }

        model.addAttribute("user", sessionInfo);
        model.addAttribute("oidcUser", oidcUser);
        model.addAttribute("activeSessions", userSessionService.getActiveSessionCount());

        if (oidcUser != null) {
            model.addAttribute("claims", oidcUser.getClaims());
            model.addAttribute("idToken", oidcUser.getIdToken().getTokenValue());
        }

        logger.info("Dashboard accessed by user: {}",
                sessionInfo != null ? sessionInfo.getEmail() : "unknown");

        return "dashboard";
    }
}

