// OidcCallbackController.java (manual flow alternative)
// ============================================================
package com.example.oidcclient.controller;

import com.example.oidcclient.config.OidcProviderConfig;
import com.example.oidcclient.model.TokenResponse;
import com.example.oidcclient.model.UserInfoResponse;
import com.example.oidcclient.model.UserSessionInfo;
import com.example.oidcclient.service.IdTokenParserService;
import com.example.oidcclient.service.TokenExchangeService;
import com.example.oidcclient.service.UserSessionService;
import org.slf4j.Logger;
import org.slf4j.LoggerFactory;
import org.springframework.web.bind.annotation.*;

import jakarta.servlet.http.HttpSession;
import java.util.HashMap;
import java.util.Map;
import java.net.URLEncoder;
import java.nio.charset.StandardCharsets;
import java.security.SecureRandom;
import java.util.Base64;

@RestController
@RequestMapping("/api/oidc")
public class OidcCallbackController {

    private static final Logger logger = LoggerFactory.getLogger(OidcCallbackController.class);

    private final OidcProviderConfig oidcProviderConfig;
    private final TokenExchangeService tokenExchangeService;
    private final IdTokenParserService idTokenParserService;
    private final UserSessionService userSessionService;

    public OidcCallbackController(OidcProviderConfig oidcProviderConfig,
                                  TokenExchangeService tokenExchangeService,
                                  IdTokenParserService idTokenParserService,
                                  UserSessionService userSessionService) {
        this.oidcProviderConfig = oidcProviderConfig;
        this.tokenExchangeService = tokenExchangeService;
        this.idTokenParserService = idTokenParserService;
        this.userSessionService = userSessionService;
    }

    @GetMapping("/authorize")
    public Map<String, String> getAuthorizationUrl(HttpSession session) {
        String state = generateSecureRandom();
        String nonce = generateSecureRandom();

        session.setAttribute("oauth2_state", state);
        session.setAttribute("oauth2_nonce", nonce);

        String authUrl = oidcProviderConfig.getAuthorizationUri()
                + "?response_type=code"
                + "&client_id=" + URLEncoder.encode(oidcProviderConfig.getClientId(), StandardCharsets.UTF_8)
                + "&redirect_uri=" + URLEncoder.encode(oidcProviderConfig.getRedirectUri(), StandardCharsets.UTF_8)
                + "&scope=" + URLEncoder.encode("openid profile email", StandardCharsets.UTF_8)
                + "&state=" + state
                + "&nonce=" + nonce;

        Map<String, String> response = new HashMap<>();
        response.put("authorizationUrl", authUrl);
        response.put("state", state);
        return response;
    }

    @GetMapping("/callback")
    public Map<String, Object> handleCallback(
            @RequestParam("code") String code,
            @RequestParam(value = "state", required = false) String state,
            HttpSession session) {

        String savedState = (String) session.getAttribute("oauth2_state");
        if (savedState != null && !savedState.equals(state)) {
            throw new RuntimeException("State parameter mismatch - potential CSRF attack");
        }

        logger.info("Received authorization code, exchanging for tokens...");
        TokenResponse tokenResponse = tokenExchangeService.exchangeAuthorizationCode(code);

        UserSessionInfo sessionInfo;
        if (tokenResponse.getIdToken() != null) {
            logger.info("Parsing ID token claims...");
            sessionInfo = idTokenParserService.parseIdToken(tokenResponse.getIdToken());
        } else {
            logger.info("No ID token received, fetching user info...");
            UserInfoResponse userInfo = tokenExchangeService.getUserInfo(tokenResponse.getAccessToken());
            sessionInfo = new UserSessionInfo();
            sessionInfo.setSubject(userInfo.getSubject());
            sessionInfo.setEmail(userInfo.getEmail());
            sessionInfo.setName(userInfo.getName());
            sessionInfo.setGivenName(userInfo.getGivenName());
            sessionInfo.setFamilyName(userInfo.getFamilyName());
            sessionInfo.setPicture(userInfo.getPicture());
            sessionInfo.setLocale(userInfo.getLocale());
            sessionInfo.setEmailVerified(userInfo.getEmailVerified() != null && userInfo.getEmailVerified());
        }

        sessionInfo.setAccessToken(tokenResponse.getAccessToken());
        sessionInfo.setRefreshToken(tokenResponse.getRefreshToken());

        userSessionService.createSession(session, sessionInfo);

        Map<String, Object> response = new HashMap<>();
        response.put("subject", sessionInfo.getSubject());
        response.put("email", sessionInfo.getEmail());
        response.put("name", sessionInfo.getName());
        response.put("sessionCreated", true);
        return response;
    }

    @GetMapping("/session")
    public Map<String, Object> getSessionInfo(HttpSession session) {
        UserSessionInfo sessionInfo = userSessionService.getSession(session);
        Map<String, Object> response = new HashMap<>();

        if (sessionInfo != null) {
            response.put("authenticated", true);
            response.put("subject", sessionInfo.getSubject());
            response.put("email", sessionInfo.getEmail());
            response.put("name", sessionInfo.getName());
            response.put("sessionCreatedAt", sessionInfo.getSessionCreatedAt());
        } else {
            response.put("authenticated", false);
        }

        return response;
    }

    @PostMapping("/refresh")
    public Map<String, Object> refreshToken(HttpSession session) {
        UserSessionInfo sessionInfo = userSessionService.getSession(session);
        if (sessionInfo == null || sessionInfo.getRefreshToken() == null) {
            throw new RuntimeException("No active session or refresh token available");
        }

        TokenResponse tokenResponse = tokenExchangeService.refreshAccessToken(sessionInfo.getRefreshToken());
        userSessionService.updateTokens(session,
                tokenResponse.getAccessToken(),
                tokenResponse.getRefreshToken());

        Map<String, Object> response = new HashMap<>();
        response.put("refreshed", true);
        response.put("expiresIn", tokenResponse.getExpiresIn());
        return response;
    }

    @PostMapping("/logout")
    public Map<String, Object> logout(HttpSession session) {
        userSessionService.invalidateSession(session);
        Map<String, Object> response = new HashMap<>();
        response.put("loggedOut", true);
        return response;
    }

    @GetMapping("/userinfo")
    public UserInfoResponse getUserInfo(HttpSession session) {
        UserSessionInfo sessionInfo = userSessionService.getSession(session);
        if (sessionInfo == null || sessionInfo.getAccessToken() == null) {
            throw new RuntimeException("No active session or access token available");
        }
        return tokenExchangeService.getUserInfo(sessionInfo.getAccessToken());
    }

    private String generateSecureRandom() {
        byte[] bytes = new byte[32];
        new SecureRandom().nextBytes(bytes);
        return Base64.getUrlEncoder().withoutPadding().encodeToString(bytes);
    }
}

